#include <stdio.h>
#include <string.h>
#include <ctype.h>

#define MAX_LENGTH 1000

// Encrypts a single character using Caesar cipher
char encrypt_char(char ch, int shift) {
    if (isupper(ch)) {
        return (char)(((ch - 'A' + shift) % 26) + 'A');
    } else if (islower(ch)) {
        return (char)(((ch - 'a' + shift) % 26) + 'a');
    }
    return ch; // Non-alphabetic characters unchanged
}

// Decrypts a single character
char decrypt_char(char ch, int shift) {
    if (isupper(ch)) {
        return (char)(((ch - 'A' - shift + 26) % 26) + 'A');
    } else if (islower(ch)) {
        return (char)(((ch - 'a' - shift + 26) % 26) + 'a');
    }
    return ch;
}

// Encrypt entire string
void caesar_encrypt(char *plaintext, char *ciphertext, int shift) {
    int i;
    for (i = 0; plaintext[i] != '\0'; i++) {
        ciphertext[i] = encrypt_char(plaintext[i], shift);
    }
    ciphertext[i] = '\0';
}

// Decrypt entire string
void caesar_decrypt(char *ciphertext, char *plaintext, int shift) {
    int i;
    for (i = 0; ciphertext[i] != '\0'; i++) {
        plaintext[i] = decrypt_char(ciphertext[i], shift);
    }
    plaintext[i] = '\0';
}

// Brute-force attack: try all 25 possible shifts
void brute_force_attack(char *ciphertext) {
    char decrypted[MAX_LENGTH];
    int shift;

    printf("\n=== Brute Force Attack (trying all 25 keys) ===\n");
    for (shift = 1; shift <= 25; shift++) {
        caesar_decrypt(ciphertext, decrypted, shift);
        printf("Shift %2d: %s\n", shift, decrypted);
    }
}

int main() {
    char plaintext[MAX_LENGTH];
    char ciphertext[MAX_LENGTH];
    char decrypted[MAX_LENGTH];
    int shift;

    // Get input from user
    printf("=== Caesar Cipher Implementation ===\n\n");
    printf("Enter plaintext: ");
    fgets(plaintext, MAX_LENGTH, stdin);
    plaintext[strcspn(plaintext, "\n")] = 0;  // Remove newline

    printf("Enter shift value (1-25): ");
    scanf("%d", &shift);

    if (shift < 1 || shift > 25) {
        printf("Invalid shift value. Using default shift = 3\n");
        shift = 3;
    }

    // Encryption
    caesar_encrypt(plaintext, ciphertext, shift);
    printf("\n=== Results ===\n");
    printf("Plaintext:  %s\n", plaintext);
    printf("Shift:      %d\n", shift);
    printf("Ciphertext: %s\n", ciphertext);

    // Decryption
    caesar_decrypt(ciphertext, decrypted, shift);
    printf("Decrypted:  %s\n", decrypted);

    // Demonstrate brute-force vulnerability
    brute_force_attack(ciphertext);

    // Example from theory: university BELGAUM with key=3
    printf("\n=== Example from Theory ===\n");
    strcpy(plaintext, "university BELGAUM");
    shift = 3;
    caesar_encrypt(plaintext, ciphertext, shift);
    printf("Plaintext 'university BELGAUM' with shift %d = '%s'\n", shift, ciphertext);

    return 0;
}

import java.util.ArrayList;
import java.util.List;

/**
 * Rail Fence Cipher - A Transposition Cipher
 * This cipher writes plaintext in a zigzag pattern on rails
 * and then reads off row by row to produce ciphertext.
 */
public class RailFenceCipher {

    /**
     * Encrypts plaintext using Rail Fence cipher
     * @param plaintext The message to encrypt
     * @param rails Number of rails to use
     * @return Encrypted ciphertext
     */
    public static String encrypt(String plaintext, int rails) {
        if (rails < 2) {
            throw new IllegalArgumentException("Rails must be at least 2");
        }

        // Create rail arrays
        List<StringBuilder> railList = new ArrayList<>();
        for (int i = 0; i < rails; i++) {
            railList.add(new StringBuilder());
        }

        // Place characters in zigzag pattern
        int currentRail = 0;
        boolean goingDown = false;

        for (char ch : plaintext.toCharArray()) {
            railList.get(currentRail).append(ch);

            // Change direction at top or bottom rail
            if (currentRail == 0 || currentRail == rails - 1) {
                goingDown = !goingDown;
            }
            currentRail += goingDown ? 1 : -1;
        }

        // Concatenate all rails
        StringBuilder ciphertext = new StringBuilder();
        for (StringBuilder rail : railList) {
            ciphertext.append(rail);
        }

        return ciphertext.toString();
    }

    /**
     * Decrypts Rail Fence ciphertext
     * @param ciphertext The encrypted message
     * @param rails Number of rails used during encryption
     * @return Decrypted plaintext
     */
    public static String decrypt(String ciphertext, int rails) {
        if (rails < 2) {
            throw new IllegalArgumentException("Rails must be at least 2");
        }

        // Calculate length of each rail
        int[] railLengths = new int[rails];
        int currentRail = 0;
        boolean goingDown = false;

        for (int i = 0; i < ciphertext.length(); i++) {
            railLengths[currentRail]++;
            if (currentRail == 0 || currentRail == rails - 1) {
                goingDown = !goingDown;
            }
            currentRail += goingDown ? 1 : -1;
        }

        // Distribute ciphertext to rails
        List<StringBuilder> railList = new ArrayList<>();
        int index = 0;
        for (int i = 0; i < rails; i++) {
            railList.add(new StringBuilder(
                ciphertext.substring(index, index + railLengths[i])));
            index += railLengths[i];
        }

        // Read in zigzag pattern to reconstruct plaintext
        StringBuilder plaintext = new StringBuilder();
        currentRail = 0;
        goingDown = false;
        int[] railIndices = new int[rails];

        for (int i = 0; i < ciphertext.length(); i++) {
            plaintext.append(railList.get(currentRail).charAt(railIndices[currentRail]));
            railIndices[currentRail]++;

            if (currentRail == 0 || currentRail == rails - 1) {
                goingDown = !goingDown;
            }
            currentRail += goingDown ? 1 : -1;
        }

        return plaintext.toString();
    }

    public static void main(String[] args) {
        // Example from theory: "ENGINEERING" with 2 rails
        String plaintext = "ENGINEERING";
        int rails = 2;

        String encrypted = encrypt(plaintext, rails);
        String decrypted = decrypt(encrypted, rails);

        System.out.println("=== Rail Fence Cipher Demo ===\n");
        System.out.println("Plaintext: " + plaintext);
        System.out.println("Rails: " + rails);
        System.out.println("Encrypted: " + encrypted);
        System.out.println("Decrypted: " + decrypted);

        // Show the zigzag pattern
        System.out.println("\n=== Zigzag Pattern ===");
        System.out.println("Plaintext: E N G I N E E R I N G");
        System.out.println("Rail 1:    E   G   E   R   G   = EGERNG");
        System.out.println("Rail 2:    N   I   N   I       = NIENI");
        System.out.println("Combined:  EGERNGNIENI = " + encrypted);

        // Example with 3 rails
        System.out.println("\n=== Example with 3 Rails ===");
        plaintext = "HELLO WORLD";
        rails = 3;
        encrypted = encrypt(plaintext, rails);
        decrypted = decrypt(encrypted, rails);
        System.out.println("Plaintext: " + plaintext);
        System.out.println("Rails: " + rails);
        System.out.println("Encrypted: " + encrypted);
        System.out.println("Decrypted: " + decrypted);
    }
}
